using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Security.Cryptography;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FileController : ControllerBase
    {
        private const string AllowedExtensions = "doc,docx,xls,xlsx,ppt,pptx,jpg,jpeg,png,gif,bmp,tiff,tif,txt,pdf";
        private readonly string _baseDirectory;

        public FileController(string baseDirectory)
        {
            _baseDirectory = baseDirectory;
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile([FromRoute] string filename)
        {
            var path = Path.Combine(_baseDirectory, filename);

            // Canonicalize the path
            path = Path.GetFullPath(path);
            if (Path.IsPathRooted(path))
                return Forbid();

            // Validate the file extension
            var extension = Path.GetExtension(filename).ToLower();
            if (!AllowedExtensions.Contains(extension))
                return Forbid();

            try
            {
                var fileInfo = new FileInfo(path);
                if (!fileInfo.Exists)
                    return NotFound();

                var mimeType = GetMimeType(fileInfo.Extension);
                return File(fileInfo.OpenRead(), mimeType, filename);
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Error reading file: {ex.Message}");
            }
        }

        private string GetMimeType(string extension)
        {
            switch (extension.ToLower())
            {
                case ".doc":
                    return "application/msword";
                case ".docx":
                    return "application/vnd.openxmlformats-officedocument.wordprocessingml.document";
                case ".xls":
                    return "application/msexcel";
                case ".xlsx":
                    return "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
                case ".ppt":
                    return "application/mspowerpoint";
                case ".pptx":
                    return "application/vnd.openxmlformats-officedocument.presentationml.presentation";
                case ".jpg":
                case ".jpeg":
                    return "image/jpeg";
                case ".png":
                    return "image/png";
                case ".gif":
                    return "image/gif";
                case ".bmp":
                    return "image/bmp";
                case ".tiff":
                case ".tif":
                    return "image/tiff";
                case ".txt":
                    return "text/plain";
                case ".pdf":
                    return "application/pdf";
                default:
                    return "application/octet-stream";
            }
        }
    }
